const config = $input.first()?.json || {};
const rawSourcesJson = (config.rssSourcesJson || '').trim();
const fallbackSources = [
  {
    feedUrl: 'http://rsshub:1200/xiaoyuzhou/podcast/648b0b641c48983391a63f98',
    sourceName: '42章经',
    sourceType: 'podcast'
  }
];

let sources = fallbackSources;
if (rawSourcesJson) {
  try {
    const parsed = JSON.parse(rawSourcesJson);
    if (!Array.isArray(parsed)) {
      throw new Error('RSS_SOURCE_URLS_JSON must be a JSON array');
    }
    sources = parsed;
  } catch (error) {
    throw new Error(`RSS_SOURCE_URLS_JSON parse failed: ${error.message}`);
  }
}

const obsidianInboxDir = (config.obsidianInboxDir || '00_Inbox/AI_Information_Processor').trim() || '00_Inbox/AI_Information_Processor';

return sources.map((source, index) => {
  const feedUrl = (source.feedUrl || source.url || '').trim();
  if (!feedUrl) {
    throw new Error(`Source ${index + 1} is missing feedUrl/url`);
  }

  return {
    json: {
      feedUrl,
      sourceName: source.sourceName || source.name || `source-${index + 1}`,
      sourceType: source.sourceType || 'rss',
      obsidianInboxDir
    }
  };
});

const stripHtml = (value = '') => value
  .replace(/<style[\s\S]*?<\/style>/gi, ' ')
  .replace(/<script[\s\S]*?<\/script>/gi, ' ')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/gi, ' ')
  .replace(/&amp;/gi, '&')
  .replace(/\s+/g, ' ')
  .trim();

const title = (($json.title || '').trim() || 'untitled');
const sourceUrl = $json.link || $json.guid || '';
const publishedAt = $json.isoDate || $json.pubDate || new Date().toISOString();
const rawHtml = [
  $json['content:encoded'],
  $json.content,
  $json.contentSnippet,
  $json.summary,
  $json.description
].find((value) => typeof value === 'string' && value.trim()) || '';

let sourceHost = 'unknown-source';
const hostMatch = String(sourceUrl).match(/^https?:\/\/([^\/?#]+)/i);
if (hostMatch?.[1]) {
  sourceHost = hostMatch[1].replace(/^www\./i, '');
}

return {
  json: {
    title,
    sourceUrl,
    sourceHost,
    publishedAt,
    author: $json.creator || $json.author || '',
    rawContent: stripHtml(rawHtml),
    rawHtml,
    originalItem: $json,
    obsidianInboxDir: $json.obsidianInboxDir || '00_Inbox/AI_Information_Processor'
  }
};

const slugify = (value = '') => value
  .toString()
  .normalize('NFKD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-zA-Z0-9\u4e00-\u9fa5]+/g, '-')
  .replace(/^-+|-+$/g, '')
  .toLowerCase();

const yamlEscape = (value = '') => value
  .toString()
  .replace(/\\/g, '\\\\')
  .replace(/"/g, '\\"');

const inboxDir = ($json.obsidianInboxDir || '00_Inbox/AI_Information_Processor').trim() || '00_Inbox/AI_Information_Processor';
const dateForFile = new Date($json.publishedAt || Date.now());
const yyyy = dateForFile.getFullYear();
const mm = String(dateForFile.getMonth() + 1).padStart(2, '0');
const dd = String(dateForFile.getDate()).padStart(2, '0');
const hh = String(dateForFile.getHours()).padStart(2, '0');
const mi = String(dateForFile.getMinutes()).padStart(2, '0');
const ss = String(dateForFile.getSeconds()).padStart(2, '0');
const timestamp = `${yyyy}-${mm}-${dd}_${hh}-${mi}-${ss}`;
const titleSlug = slugify($json.title).slice(0, 80) || 'untitled';
const fileBaseName = `${timestamp}_${titleSlug}`;
const excerpt = ($json.rawContent || '').slice(0, 280).trim();
const tags = ['inbox', 'ai-information-processor', 'raw-ingest', slugify($json.sourceHost)].filter(Boolean);
const authorLine = $json.author ? `author: \"${yamlEscape($json.author)}\"\n` : '';
const sourceUrl = $json.sourceUrl || '';
const markdown = `---\ntitle: \"${yamlEscape($json.title)}\"\nsource: \"${yamlEscape($json.sourceHost)}\"\nsource_url: \"${yamlEscape(sourceUrl)}\"\npublished_at: \"${new Date($json.publishedAt).toISOString()}\"\ningested_at: \"${new Date().toISOString()}\"\nworkflow: \"rss-to-obsidian-raw\"\nstatus: \"raw\"\n${authorLine}tags:\n${tags.map((tag) => `  - ${tag}`).join('\n')}\n---\n\n# ${$json.title}\n\n> Source: ${sourceUrl ? `[${$json.sourceHost}](${sourceUrl})` : $json.sourceHost}\n\n## Excerpt\n\n${excerpt || 'No text excerpt extracted.'}\n\n## Raw Content\n\n${$json.rawContent || 'No text content extracted from this feed item.'}\n`;

return {
  json: {
    ...$json,
    fileBaseName,
    relativeFilePath: `${inboxDir}/${fileBaseName}.md`
  },
  binary: {
    data: {
      data: Buffer.from(markdown, 'utf8').toString('base64'),
      mimeType: 'text/markdown',
      fileName: `${fileBaseName}.md`,
      fileExtension: 'md'
    }
  }
};
